            var next = keyframes[index + 1];
            if (frame > next.Frame)
            {
                continue;
            }

            if (current.Easing == EaseMode.Step || Mathf.Approximately(current.Value, next.Value))
            {
                return current.Value;
            }

            var t = Mathf.InverseLerp(current.Frame, next.Frame, frame);
            return Mathf.LerpUnclamped(current.Value, next.Value, Ease(t, current.Easing));
        }

        return keyframes[keyframes.Length - 1].Value;
    }

