            EaseMode.EaseIn => t * t * t,
            EaseMode.EaseOut => 1f - Mathf.Pow(1f - t, 3f),
            EaseMode.EaseInOut => t < 0.5f ? 4f * t * t * t : 1f - Mathf.Pow(-2f * t + 2f, 3f) / 2f,
            EaseMode.Step => 0f,
            _ => t
